  ('retired-d0d1b9a2-moex-00250', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '甲公司正考慮是否接受一特殊訂單，該訂單數量 800 單位，單位售價$90，公司正常每單位 售價為$100。在現有產能水準下，產品每單位變動成本為$40，每單位固定成本為$6，該特別 訂單並不會增加銷管費用。已知甲公司沒有其他閒置產能接此特殊訂單，下列何者為甲公司 接下此特殊訂單，對公司獲利之影響？ $40,000  $35,200  $3,200  $8,000', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "19c05038aca8", "answer_pdf_sha1": "f1cefa6faf33", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
