  ('retired-d0d1b9a2-moex-00253', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '甲公司A部門長久以來一直都處於虧損狀態，公司管理部門X1年底考慮將其關閉。X1年該 部門有邊際貢獻$50,000，固定成本$83,000。固定成本中有$52,000是來自公司整體共同成本的 分攤，另A部門對外無跨年度之合約承諾。若甲公司將A部門關閉，對該公司X2年整體利 潤而言，下列敘述何者正確？ $33,000  $33,000  $19,000  $19,000', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "19c05038aca8", "answer_pdf_sha1": "f1cefa6faf33", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00254', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-194ec0d9', 'sub-retired-d0d1b9a2-08', NULL, 'single_choice', '有關經濟訂購量模型之敘述，下列何者正確？', '["最適經濟訂購量下，總攸關訂購成本一定等於總攸關持有成本", "總攸關持有成本與每次訂購量呈線性關係", "總攸關訂購成本與每次訂購量呈線性關係", "存貨總攸關成本與每次訂購量呈線性關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "19c05038aca8", "answer_pdf_sha1": "f1cefa6faf33", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
